import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation, } from '@angular/core';
let nextUid = 0;
/**
 * Barre de progression basée sur l'élément `<progress>` natif
 * (cf. décision G.2). Mode indéterminé en omettant `value`.
 */
let PfProgressComponent = class PfProgressComponent {
    constructor() {
        this.value = null;
        this.max = 100;
        this.label = '';
        this.showValue = null;
        this.id = '';
        this.autoId = `pf-progress-${++nextUid}`;
    }
    get progressId() {
        return this.id || this.autoId;
    }
    get displayValue() {
        if (this.value === null)
            return 0;
        return Math.round((this.value / this.max) * 100);
    }
    get shouldShowValue() {
        if (this.showValue !== null)
            return this.showValue;
        return Boolean(this.label) && this.value !== null;
    }
