    @if (label) {
      <div class="ds-progress-wrap">
        <div class="ds-progress__label">
          <label [attr.for]="progressId">{{ label }}</label>
          @if (shouldShowValue) {
            <span class="ds-progress__value">{{ displayValue }}%</span>
          }
        </div>
        <progress
          [id]="progressId"
          class="ds-progress"
          [value]="value !== null ? value : null"
          [max]="max"
        ></progress>
      </div>
    } @else {
      <progress
        [id]="progressId"
        class="ds-progress"
        [value]="value !== null ? value : null"
        [max]="max"
      ></progress>
    }
  `,
    })
